#include<bits/stdc++.h>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define drep(a,b,c) for(int c=(a);c>=(b);--c)
#define int long long
using namespace std;
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
const int N=1e6+10;
int cat,hil,ple,s[N],a[N],dis[N],dp[N],g[N];
inline long double Cnt(int i,int j){return (long double)(g[i]+s[i]-g[j]-s[j])/(i-j);}
int deq[N],H,T;
signed main()
{
//	freopen("data.txt","r",stdin);
//	freopen("b.txt","w",stdout);
	hil=read();cat=read();ple=read();
	rep(2,hil,i)dis[i]=dis[i-1]+read();
	rep(1,cat,i){int h=read(),x=read();a[i]=x-dis[h];}
	sort(a+1,a+cat+1);rep(1,cat,i)s[i]=s[i-1]+a[i];
	rep(1,cat,i)dp[i]=(a[i]*i-s[i]);//printf("1 :: ");rep(1,cat,i)printf("%lld ",dp[i]);puts("");
	rep(2,ple,tt)
	{
		memcpy(g,dp,(cat+1)<<3);deq[H=T=1]=1;
		rep(2,cat,i)
		{
			while(H<T&&Cnt(deq[H],deq[H+1])<(long double)a[i])H++;
			dp[i]=g[deq[H]]+a[i]*(i-deq[H])-s[i]+s[deq[H]];
			while(H<T&&Cnt(deq[T],i)<Cnt(deq[T],deq[T-1]))--T;
			deq[++T]=i;
		}
//		printf("%d :: ",tt);rep(1,cat,i)printf("%lld ",dp[i]);puts("");
	}
//	rep(1,cat,i)printf("%lld ",a[i]);puts("");
	
	printf("%lld\n",dp[cat]);return 0;
}
